import { BarRenderer } from '../bar/bar-parser';
import { setBoxplotBuilderConfig } from './boxplot-builder-config';
import { boxplot_encode_collectors } from './boxplot-encode-helpers';
import { setBulletBuilderConfig } from '../bullet/bullet-builder-config';

export class BoxplotRenderer extends BarRenderer {
    initialize(container) {
        super.initialize(container);
        this.rangeYType = true;
    }

    collectEncode() {
        setBulletBuilderConfig.call(this);
        setBoxplotBuilderConfig.call(this);
        boxplot_encode_collectors.call(this);
    }
    getAllowedMarkOperator() {
        return ['levelmarker', 'bar', 'median', 'whisker'];
    }
}
